    }
    nint ntotal = default!;
    while (builtin.len(p) > 0 && b.size > 0) {
        var readFrom = b.bytesFromFirstChunk();
        nint n = copy(p, readFrom);
        p = p[(int)(n)..];
        ntotal += n;
        b.r += n;
        b.size -= n;
        // If the first chunk has been consumed, advance to the next chunk.
        if (b.r == builtin.len(b.chunks[0])) {
            http2putDataBufferChunk(b.chunks[0]);
            nint end = builtin.len(b.chunks) - 1;
            copy(b.chunks[..(int)(end)], b.chunks[1..]);
            b.chunks[end] = default!;
            b.chunks = b.chunks[..(int)(end)];
            b.r = 0;
        }
    }
    return (ntotal, default!);
}

[GoRecv] internal static slice<byte> bytesFromFirstChunk(this ref http2dataBuffer b) {
    if (builtin.len(b.chunks) == 1) {
        return b.chunks[0][(int)(b.r)..(int)(b.w)];
    }
    return b.chunks[0][(int)(b.r)..];
}

// Len returns the number of bytes of the unread portion of the buffer.
[GoRecv] internal static nint Len(this ref http2dataBuffer b) {
    return b.size;
}

// Write appends p to the buffer.
[GoRecv] internal static (nint, error) Write(this ref http2dataBuffer b, slice<byte> p) {
    nint ntotal = builtin.len(p);
    while (builtin.len(p) > 0) {
        // If the last chunk is empty, allocate a new chunk. Try to allocate
        // enough to fully copy p plus any additional bytes we expect to
        // receive. However, this may allocate less than len(p).
        var want = (int64)builtin.len(p);
        if (b.expected > want) {
            want = b.expected;
        }
        var chunk = b.lastChunkOrAlloc(want);
        nint n = copy(chunk[(int)(b.w)..], p);
        p = p[(int)(n)..];
        b.w += n;
        b.size += n;
        b.expected -= (int64)n;
    }
    return (ntotal, default!);
}

[GoRecv] internal static slice<byte> lastChunkOrAlloc(this ref http2dataBuffer b, int64 want) {
    if (builtin.len(b.chunks) != 0) {
        var last = b.chunks[builtin.len(b.chunks) - 1];
        if (b.w < builtin.len(last)) {
            return last;
        }
    }
    var chunk = http2getDataBufferChunk(want);
    b.chunks = append(b.chunks, chunk);
    b.w = 0;
    return chunk;
}

