[GoRecv] internal static (nint n, error err) Write(this ref http2bufferedWriter w, slice<byte> p) {
    nint n = default!;
    error err = default!;

    if (w.bw == nil) {
        var bw = Ꮡhttp2bufWriterPool.Get()._<ж<bufio.Writer>>();
        bw.Reset(w.w);
        w.bw = bw;
    }
