[GoRecv] internal static error Flush(this ref http2bufferedWriter w) {
    var bw = w.bw;
    if (bw == nil) {
        return default!;
    }
    var err = bw.Flush();
    bw.Reset(default!);
    Ꮡhttp2bufWriterPool.Put(bw);
    w.bw = default!;
    return err;
}

