// pipe is a goroutine-safe io.Reader/io.Writer pair. It's like
// io.Pipe except there are no PipeReader/PipeWriter halves, and the
// underlying buffer is an interface. (io.Pipe is always unbuffered)
[GoType] partial struct http2pipe {
    internal sync.Mutex mu;
    internal sync.Cond c;       // c.L lazily initialized to &p.mu
    internal http2pipeBuffer b; // nil when done reading
    internal nint unread;            // bytes unread when done
    internal error err;           // read error once empty. non-nil means closed.
    internal error breakErr;           // immediate read error (caller doesn't see rest of b)
    internal channel<EmptyStruct> donec; // closed on error
    internal Action readFn;          // optional code to run in Read before error
}

[GoType] partial interface http2pipeBuffer :
    io.Writer,
    io.Reader,
    io.ReadWriter
{
    nint Len();
}

// setBuffer initializes the pipe buffer.
// It has no effect if the pipe is already closed.
internal static void setBuffer(this ж<http2pipe> Ꮡp, http2pipeBuffer b) => func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

    Ꮡp.of(http2pipe.Ꮡmu).Lock();
    defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
    if (p.err != default! || p.breakErr != default!) {
        return;
    }
    p.b = b;
});

internal static nint Len(this ж<http2pipe> Ꮡp) => func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

    Ꮡp.of(http2pipe.Ꮡmu).Lock();
    defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
    if (p.b == default!) {
        return p.unread;
    }
    return p.b.Len();
});

// Read waits until data is available and copies bytes
// from the buffer into p.
internal static (nint n, error err) Read(this ж<http2pipe> Ꮡp, slice<byte> d) {
    nint n = default!;
    error err = default!;
    func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

        Ꮡp.of(http2pipe.Ꮡmu).Lock();
        defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
        if (p.c.L == default!) {
            p.c.L = new sync_MutexжLocker(Ꮡp.of(http2pipe.Ꮡmu));
        }
        while (ᐧ) {
            if (p.breakErr != default!) {
                (n, err) = (0, p.breakErr); return;
            }
            if (p.b != default! && p.b.Len() > 0) {
                (n, err) = p.b.Read(d); return;
            }
            if (p.err != default!) {
                if (p.readFn != default!) {
                    p.readFn();
                    // e.g. copy trailers
                    p.readFn = default!;
                }
                // not sticky like p.err
                p.b = default!;
                (n, err) = (0, p.err); return;
            }
            Ꮡp.of(http2pipe.Ꮡc).Wait();
        }
    });
    return (n, err);
}

internal static error http2errClosedPipeWrite = errors.New("write on closed buffer"u8);
internal static error http2errUninitializedPipeWrite = errors.New("write on uninitialized buffer"u8);

// Write copies bytes from p into the buffer and wakes a reader.
// It is an error to write more data than the buffer can hold.
internal static (nint n, error err) Write(this ж<http2pipe> Ꮡp, slice<byte> d) {
    nint n = default!;
    error err = default!;
    func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

        Ꮡp.of(http2pipe.Ꮡmu).Lock();
        defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
        if (p.c.L == default!) {
            p.c.L = new sync_MutexжLocker(Ꮡp.of(http2pipe.Ꮡmu));
        }
        defer(Ꮡp.of(http2pipe.Ꮡc).Signal);
        if (p.err != default! || p.breakErr != default!) {
            (n, err) = (0, http2errClosedPipeWrite); return;
        }
        // pipe.setBuffer is never invoked, leaving the buffer uninitialized.
        // We shouldn't try to write to an uninitialized pipe,
        // but returning an error is better than panicking.
        if (p.b == default!) {
            (n, err) = (0, http2errUninitializedPipeWrite); return;
        }
        (n, err) = p.b.Write(d);
    });
    return (n, err);
}

// CloseWithError causes the next Read (waking up a current blocked
// Read if needed) to return the provided err after all data has been
// read.
//
// The error must be non-nil.
internal static void CloseWithError(this ж<http2pipe> Ꮡp, error err) {
    Ꮡp.closeWithError(Ꮡp.of(http2pipe.Ꮡerr), err, default!);
}

// BreakWithError causes the next Read (waking up a current blocked
// Read if needed) to return the provided err immediately, without
// waiting for unread data.
internal static void BreakWithError(this ж<http2pipe> Ꮡp, error err) {
    Ꮡp.closeWithError(Ꮡp.of(http2pipe.ᏑbreakErr), err, default!);
}

// closeWithErrorAndCode is like CloseWithError but also sets some code to run
// in the caller's goroutine before returning the error.
internal static void closeWithErrorAndCode(this ж<http2pipe> Ꮡp, error err, Action fn) {
    Ꮡp.closeWithError(Ꮡp.of(http2pipe.Ꮡerr), err, fn);
}

internal static void closeWithError(this ж<http2pipe> Ꮡp, ж<error> Ꮡdst, error err, Action fn) => func((defer, recover) => {
    ref var p = ref Ꮡp.Value;
    ref var dst = ref Ꮡdst.DerefOrNil();

    if (err == default!) {
        throw panic("err must be non-nil");
    }
    Ꮡp.of(http2pipe.Ꮡmu).Lock();
    defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
    if (p.c.L == default!) {
        p.c.L = new sync_MutexжLocker(Ꮡp.of(http2pipe.Ꮡmu));
    }
    defer(Ꮡp.of(http2pipe.Ꮡc).Signal);
    if (dst != default!) {
        // Already been done.
        return;
    }
    p.readFn = fn;
    if (Ꮡdst == Ꮡp.of(http2pipe.ᏑbreakErr)) {
        if (p.b != default!) {
            p.unread += p.b.Len();
        }
        p.b = default!;
    }
    dst = err;
    p.closeDoneLocked();
});

// requires p.mu be held.
[GoRecv] internal static void closeDoneLocked(this ref http2pipe p) {
    if (p.donec == default!) {
        return;
    }
    // Close if unclosed. This isn't racy since we always
    // hold p.mu while closing.
    switch (ᐧ) {
    case ᐧ when p.donec.ꟷᐳ(out _): {
        break;
    }
    default: {
        builtin.close(p.donec);
        break;
    }}
}

// Err returns the error (if any) first set by BreakWithError or CloseWithError.
internal static error Err(this ж<http2pipe> Ꮡp) => func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

    Ꮡp.of(http2pipe.Ꮡmu).Lock();
    defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
    if (p.breakErr != default!) {
        return p.breakErr;
    }
    return p.err;
});

// Done returns a channel which is closed if and when this pipe is closed
// with CloseWithError.
internal static /*<-*/channel<EmptyStruct> Done(this ж<http2pipe> Ꮡp) => func((defer, recover) => {
    ref var p = ref Ꮡp.Value;

    Ꮡp.of(http2pipe.Ꮡmu).Lock();
    defer(Ꮡp.of(http2pipe.Ꮡmu).Unlock);
    if (p.donec == default!) {
        p.donec = new channel<EmptyStruct>(1);
        if (p.err != default! || p.breakErr != default!) {
            // Already hit an error.
            p.closeDoneLocked();
        }
    }
    return p.donec;
});

