        headerBlock = headerBlock[(int)(builtin.len(frag))..];
        {
            var err = fn(ctx, frag, first, builtin.len(headerBlock) == 0); if (err != default!) {
                return err;
            }
        }
        first = false;
    }
    return default!;
}

